/**
 * 获取用户的打卡列表
 * GET /api/checkins?user_id=xxx&year=2024&month=1
 */
async function getCheckins(request, env) {
  const origin = request.headers.get('Origin')

  try {
    const url = new URL(request.url)
    const userId = url.searchParams.get('user_id')
    const year = url.searchParams.get('year')
    const month = url.searchParams.get('month')

    if (!userId) {
      return setCorsHeaders(errorResponse('缺少 user_id 参数'), origin)
    }

    let query = 'SELECT * FROM checkins WHERE user_id = ?'
    const params = [userId]

    if (year && month) {
      const startDate = `${year}-${month.padStart(2, '0')}-01`
      const endDate = month === '12'
        ? `${parseInt(year) + 1}-01-01`
        : `${year}-${(parseInt(month) + 1).toString().padStart(2, '0')}-01`
      query += ' AND date >= ? AND date < ?'
      params.push(startDate, endDate)
    }

    query += ' ORDER BY date DESC'

    const result = await env.DB.prepare(query).bind(...params).all()

    return setCorsHeaders(jsonResponse({ success: true, data: result.results || [] }), origin)

  } catch (error) {
    console.error('获取打卡列表失败:', error)
    return setCorsHeaders(errorResponse('获取失败', 500), origin)
  }
}

