/**
 * 创建评价
 * POST /api/reviews
 * Body: { from_user_id, to_user_id, event_id, rating, comment }
 */
async function createReview(request, env) {
  const origin = request.headers.get('Origin')

  try {
    const data = await request.json()
    const { from_user_id, to_user_id, event_id, rating, comment } = data

    if (rating < 1 || rating > 5) {
      return setCorsHeaders(errorResponse('评分必须在1-5之间'), origin)
    }

    const id = generateId()
    const now = new Date().toISOString()

    await env.DB.prepare(`
      INSERT INTO reviews (id, from_user_id, to_user_id, event_id, rating, comment, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    `).bind(id, from_user_id, to_user_id, event_id, rating, comment, now).run()

    return setCorsHeaders(jsonResponse({ success: true, data: { id } }), origin)

  } catch (error) {
    console.error('创建评价失败:', error)
    return setCorsHeaders(errorResponse('创建失败', 500), origin)
  }
}

/**
 * 获取用户收到的评价
 * GET /api/reviews?to_user_id=xxx
 */
async function getReviews(request, env) {
  const origin = request.headers.get('Origin')

  try {
    const url = new URL(request.url)
    const toUserId = url.searchParams.get('to_user_id')

    if (!toUserId) {
      return setCorsHeaders(errorResponse('缺少 to_user_id 参数'), origin)
    }

    const reviews = await env.DB.prepare(`
      SELECT r.*, u.nickname as from_nickname, u.avatar as from_avatar
      FROM reviews r
      LEFT JOIN users u ON r.from_user_id = u.id
      WHERE r.to_user_id = ?
      ORDER BY r.created_at DESC
    `).bind(toUserId).all()

    return setCorsHeaders(jsonResponse({ success: true, data: reviews.results || [] }), origin)

  } catch (error) {
    console.error('获取评价失败:', error)
    return setCorsHeaders(errorResponse('获取失败', 500), origin)
  }
}

// ==================== 主路由 ====================

export default {
  async fetch(request, env, ctx) {
    const origin = request.headers.get('Origin')

    // 处理 CORS 预检请求
    if (request.method === 'OPTIONS') {
      return new Response(null, {
        status: 204,
        headers: {
          'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
          'Access-Control-Allow-Headers': 'Content-Type, Authorization',
          'Access-Control-Max-Age': '86400',
        }
      })
    }

    const url = new URL(request.url)
    const path = url.pathname

    // 健康检查
    if (path === '/health' && request.method === 'GET') {
      return new Response(JSON.stringify({ status: 'ok' }), {
        headers: { 'Content-Type': 'application/json' }
      })
    }

    // 验证码 API
    if (path === '/api/sms/send' && request.method === 'POST') {
      return sendSmsCode(request, env)
    }
    if (path === '/api/sms/verify' && request.method === 'POST') {
      return verifySmsCode(request, env)
    }

    // 用户 API
    const userMatch = path.match(/^\/api\/users\/([^/]+)$/)
    if (userMatch && request.method === 'GET') {
      return getUser(request, env, userMatch[1])
    }
    if (userMatch && request.method === 'PUT') {
      return updateUser(request, env, userMatch[1])
    }

    // 活动 API
    if (path === '/api/events' && request.method === 'GET') {
      return getEvents(request, env)
    }
    if (path === '/api/events' && request.method === 'POST') {
      return createEvent(request, env)
    }

    const eventMatch = path.match(/^\/api\/events\/([^/]+)$/)
    if (eventMatch && request.method === 'GET') {
      return getEvent(request, env, eventMatch[1])
    }
    if (eventMatch && request.method === 'PUT') {
      return updateEvent(request, env, eventMatch[1])
    }

    const eventSignupsMatch = path.match(/^\/api\/events\/([^/]+)\/signups$/)
    if (eventSignupsMatch && request.method === 'GET') {
      return getEventSignups(request, env, eventSignupsMatch[1])
    }

    // 报名 API
    if (path === '/api/signups' && request.method === 'POST') {
      return createSignup(request, env)
    }

    const signupMatch = path.match(/^\/api\/signups\/([^/]+)$/)
    if (signupMatch && request.method === 'DELETE') {
      return deleteSignup(request, env, signupMatch[1])
    }

    // 打卡 API
    if (path === '/api/checkins' && request.method === 'GET') {
      return getCheckins(request, env)
    }
    if (path === '/api/checkins' && request.method === 'POST') {
      return createCheckin(request, env)
    }

    const checkinMatch = path.match(/^\/api\/checkins\/([^/]+)$/)
    if (checkinMatch && request.method === 'GET') {
      return getCheckin(request, env, checkinMatch[1])
    }
    if (checkinMatch && request.method === 'DELETE') {
      return deleteCheckin(request, env, checkinMatch[1])
    }

    // 相遇记录 API
    if (path === '/api/encounters' && request.method === 'GET') {
      return getEncounters(request, env)
    }
    if (path === '/api/encounters' && request.method === 'POST') {
      return createEncounter(request, env)
    }

    // 评价 API
    if (path === '/api/reviews' && request.method === 'GET') {
      return getReviews(request, env)
    }
    if (path === '/api/reviews' && request.method === 'POST') {
      return createReview(request, env)
    }

    // 404
    return setCorsHeaders(errorResponse('Not found', 404), origin)
  }
}
